options.css:
  .main {
        width: 100%;
        height: 100%;
      }
      .container {
        display: block;
        position: relative;
        container-type: inline-size;
         transform: translateY(1.75cm);
      }
      .flow-tile {
        width: 20cqi;
        height: 20cqi;
        object-fit: cover;
        position: absolute;
      }
	  .irradiance-data {
        transform: translateX(33cqi) translateY(5cqi);
      }
	  .expected-data {
        transform: translateX(17cqi) translateY(30cqi);
      }

      .sun {
        width: 22cqi;
        height: 22cqi;
        transform: translateX(calc(25cqi - 11cqi))
          translateY(calc(10cqi - 11cqi));
      }
	  .moon {
        width: 22cqi;
        height: 22cqi;
        transform: translateX(calc(25cqi - 11cqi))
          translateY(calc(10cqi - 11cqi));
      }
      .solar-data {
        transform: translateX(55cqi) translateY(50cqi);
      }
      .panel {
        width: 18cqi;
        height: 18cqi;
        transform: translateX(calc(50cqi - 9cqi)) translateY(calc(30cqi - 9cqi));
      }

      .meter {
        width: 18cqi;
        height: 18cqi;
        transform: translateX(calc(50cqi - 9cqi)) translateY(calc(55cqi - 9cqi));
      }

      .grid {
        transform: translateX(calc(25cqi - 9cqi)) translateY(calc(75cqi - 9cqi));
      }

      .factory {
        transform: translateX(calc(75cqi - 9cqi)) translateY(calc(75cqi - 9cqi));
      }

      .solar-flow,
      .expected-flow,
      .solarpower-flow-path,
      .gridpower-flow-path {
        stroke-dasharray: 7;
        stroke-dashoffset: 100;
        animation: pathAnimation 5s linear infinite;
      }

      @keyframes pathAnimation {
        to {
          stroke-dashoffset: 0;
        }
      }

      .info {
        position: absolute;
        display: flex;
        flex-direction: column;
        align-items: center;
        justify-content: center;
      }
      .grid-data {
        transform: translateX(08cqi) translateY(59cqi);
      }
	  .grid-import {
        transform: translateX(41cqi) translateY(82cqi);
      }

options.onInit:
// Sets the text from customProperties
const htmlgraphicsText = htmlNode.getElementById('htmlgraphics-text');

if (htmlgraphicsText) {
  htmlgraphicsText.textContent = customProperties.text;

  // Change the text color based on the theme
  if (theme.isDark) {
    htmlgraphicsText.style.color = 'green';
  } else {
    htmlgraphicsText.style.color = 'red';
  }
}

options.onRender:
const fields = data.series[0].fields;

const spanMap = {
  'grid-export-value': 1,
  'grid-power-value': 2,
  'insolation-value': 3,
  'irradiance-value': 4,
  'expected-energy-value': 5,
  'expected-power-value': 6,
  'grid-import-value': 7,
  'solar-power-value': 8,
  'solar-energy-value': 9,
};

// Update HTML values
Object.entries(spanMap).forEach(([id, idx]) => {
  const el = htmlNode.getElementById(id);
  if (el && fields[idx]) {
    let val = fields[idx].values.get(fields[idx].values.length - 1);

    if (typeof val === "number") {
      if (
        ['irradiance-value','expected-power-value','solar-power-value','grid-power-value','expected-energy-value'].includes(id) &&
        val < 0
      ) {
        val = 0;
      }

      if (id === 'insolation-value') {
        val = val.toFixed(1);
      } else {
        val = Math.round(val);
      }
      val = Number(val).toLocaleString()
    }

    el.textContent = val;
  }
});

// Helper to get value
function getValue(idx) {
  if (!fields[idx]) return 0;
  return fields[idx].values.get(fields[idx].values.length - 1);
}

// Flow values
const irradiance = getValue(4);
const expectedPower = getValue(6);
const solarpower = getValue(8); // 
const gridpower = getValue(2);

// Control flow helper
function controlFlow(selector, value, color) {
  htmlNode.querySelectorAll(selector).forEach(p => {
    if (value <= 0) {
      p.style.animation = "none";
      p.style.stroke = "#999da0"; // static grey
    } else {
      p.style.stroke = color;
      p.style.animation = "none";
      p.offsetHeight; // force reflow
      p.style.animation = "pathAnimation 5s linear infinite";
    }
  });
}

// Apply flows
controlFlow(".solar-flow", irradiance, "#FFA500");       // orange
controlFlow(".expected-flow", expectedPower, "#E6FF02"); // dark orange
controlFlow(".solarpower-flow-path", solarpower, "#32CD32"); // lime green

// Grid import flow
if (gridpower >= 0) {
  controlFlow(".gridpower-flow-path", 0, "#999da0"); // grey
} else {
  controlFlow(".gridpower-flow-path", gridpower, "#FF4500"); // red-orange

  // Special case: if grid import < 1, show grid power arrows as well
  if (gridpower < 1) {
    controlFlow(".gridpower-flow-path", 1, "#FF0000"); // choose color for grid power arrows
  }
}

const sun = htmlNode.getElementById("sun-icon");
const moon = htmlNode.getElementById("moon-icon");

if (sun && moon) {
  let val = getValue(spanMap['irradiance-value']);

  if (val > 0) {
    sun.style.display = "block";
    moon.style.display = "none";
  } else {
    sun.style.display = "none";
    moon.style.display = "block";
  }
}
const gridImportEl = htmlNode.getElementById("grid-importpower-value");

if (gridImportEl) {
  if (gridpower < 0) {
    gridImportEl.textContent = Math.trunc(gridpower).toLocaleString();
  } else {
    gridImportEl.textContent = "0 "; // or ""
  }
}
